SELECT

FROM exchange_rate
WHERE currency_code = #{currencyCode}
  AND target_currency = #{targetCurrency}
  AND provider = #{provider}
  AND fetched_at >= #{fetchedStart}
  AND fetched_at < #{fetchedEnd}
ORDER BY fetched_at DESC, exchange_rate_id DESC
LIMIT 1

